export const docsGuide = {"categories":[{"title":"Getting started","stories":[{"id":"create-identity","title":"Create your identity","introHtml":"<p>Register a WebAuthn passkey — no password, ever. Your OpenApe ID becomes the DDISA authority for your identity: every Service Provider logs you in via DNS-discovered SSO without ever seeing a credential.</p>\n","steps":[{"title":"Open OpenApe ID","html":"The landing page asks for nothing but your email. Click <strong>Create account</strong> to start.","shot":"/docs/screenshots/create-identity/01-landing.png"},{"title":"Request your registration link","html":"Enter your email — OpenApe ID sends you a one-time registration link.","shot":"/docs/screenshots/create-identity/02-request-link.png"},{"title":"Register your passkey","html":"The link opens the passkey ceremony. Your device (Touch ID, Windows Hello, a security key) creates the credential — in this E2E run a virtual authenticator answers headlessly.","shot":"/docs/screenshots/create-identity/03-register-passkey.png"},{"title":"Done — you are signed in","html":"That&#39;s the whole sign-up: one passkey, no password to remember or leak.","shot":"/docs/screenshots/create-identity/04-registered.png"}]}]},{"title":"Account","stories":[{"id":"account-dashboard","title":"Your account dashboard","introHtml":"<p>The dashboard is home base for your identity: passkeys, agent identities, permissions and connected services.</p>\n","steps":[{"title":"Open your dashboard","html":"Signed in, the root page shows your account: registered passkeys, the agents acting under your identity, and the services you have authorized.","shot":"/docs/screenshots/account-dashboard/01-dashboard.png"}]}]},{"title":"Agents","stories":[{"id":"agent-identities","title":"Your agent identities","introHtml":"<p>Agents are first-class identities under your account: the IdP mints them a DDISA email and you stay in control.</p>\n","steps":[{"title":"Open Agents at your IdP","html":"Every agent spawned from your nests appears here with its own <code>…@id.openape.ai</code> identity — inspect it, or revoke it independently of your own keys.","shot":"/docs/screenshots/agent-identities/01-agents.png"}]}]}]}
